SELECT transfer_id, token_id, source_address, destination_address, amount, transfer_date
FROM token_transfers
WHERE status = 'completed' AND source_chain_id = 'solana';

SELECT token_id, COUNT(*) AS transfer_count
FROM token_transfers
GROUP BY token_id;

SELECT token_id, SUM(amount)
FROM token_transfers
GROUP BY token_id;

SELECT COUNT(*) AS active_tokens 
FROM tokens 
WHERE is_active = 1;

SELECT user_id, COUNT(*) AS number_of_transfers
FROM token_transfers
GROUP BY user_id;

SELECT t.name
FROM tokens t
JOIN token_balances tb ON t.token_id = tb.token_id
WHERE tb.balance = (
  SELECT MAX(balance) FROM token_balances
);

SELECT COUNT(*) AS total_transactions
FROM token_transfers
WHERE transfer_date BETWEEN '2023-09-01 00:00:00' AND '2023-09-30 23:59:59';

SELECT name, symbol
FROM tokens
WHERE token_id > 50 AND is_active = 1;

SELECT COUNT(*)
FROM token_transfers
WHERE is_cross_chain = 0 AND transfer_date = '2023-10-02 15:30:00';

SELECT * 
FROM tokens 
WHERE token_id = 1;

SELECT DISTINCT tokens.symbol, tokens.name
FROM tokens
JOIN token_transfers ON tokens.token_id = token_transfers.token_id;

SELECT DISTINCT token_id 
FROM token_transfers 
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');

SELECT name, symbol
FROM tokens
WHERE is_active = 1 AND chain_id = 'solana';

SELECT AVG(balance) AS average_balance
FROM token_balances
WHERE user_id = 1;
